import { type PropsWithChildren, useLayoutEffect, useRef } from 'react';

import { useId } from '../../../../../core/hooks/useId.js';
import { useMergeRefs } from '../../../../../core/hooks/useMergeRefs.js';
import { useFontSizeForContainer } from '../../../hooks/useFontSizeForContainer.js';
import { useThrottledResizeObserver } from '../../../hooks/useThrottledResizeObserver.js';
import {
  DEFAULT_MAX_VALUE_FONT_SIZE,
  FONT_HEIGHT_RATIO,
  FONT_WIDTH_RATIO,
} from '../constants.js';
import { FontSizeContext } from '../contexts/font-size.context.js';
import { useGlobalFontSize } from '../hooks/use-global-font-size.js';

/**
 * Given a text, it will provide a refCallback to observe the size of a container element, to give the proper fontSize to the text
 *
 * @param text - value text
 * @param suffix - unit text
 * @param children -
 */
export const FontSizeProvider = ({
  text,
  suffix,
  children,
}: PropsWithChildren<{
  text: string;
  suffix?: string;
}>) => {
  const ref = useRef<HTMLDivElement>(null);

  const { refCallback, width = 0, height = 0 } = useThrottledResizeObserver();

  const mergedRef = useMergeRefs<HTMLElement | null>([refCallback, ref]);

  let preferredFontSize = useFontSizeForContainer({
    container: {
      width: width * FONT_WIDTH_RATIO,
      height: height * FONT_HEIGHT_RATIO,
    },
    text,
    element: ref.current?.querySelector('span'), // element containing text font style
    suffix,
    suffixElement: ref.current?.querySelector('small'), // element containing suffix font style
  });

  if (text.length === 0 || text === '00') {
    preferredFontSize = DEFAULT_MAX_VALUE_FONT_SIZE;
  }

  const id = useId();
  const { updateValueFontSize } = useGlobalFontSize();

  useLayoutEffect(() => {
    if (height && width) {
      updateValueFontSize?.(id, preferredFontSize);
    }
  }, [height, width, preferredFontSize]);

  return (
    <FontSizeContext.Provider
      value={{
        fontSize: preferredFontSize,
        refCallback: mergedRef,
      }}
    >
      {children}
    </FontSizeContext.Provider>
  );
};
